+    }
+
+    pub fn minimal_40x12() -> OptimizedBuffer {
+        OptimizedBuffer::new(40, 12)
+    }
+
+    pub fn large_200x60() -> OptimizedBuffer {
+        OptimizedBuffer::new(200, 60)
+    }
+}
